python3 -c "
import sys, json, re, os
try:
    payload = json.load(sys.stdin)
    path = payload.get('tool_input',{}).get('file_path','') or payload.get('tool_input',{}).get('file_path','')
    if not path:
        sys.exit(0)
    if 'backlog/' not in path or not path.endswith('.md'):
        sys.exit(0)
    fname = os.path.basename(path)
    errors = []
    if not re.match(r'^\d{3}-', fname):
        errors.append('BACKLOG: filename must start with a 3-digit number (e.g. 001-title.md)')
    try:
        content = open(path).read()
        for section in ['**Status:**', '**Estimate:**', '## Task Breakdown', '## Spec']:
            if section not in content:
                errors.append(f'BACKLOG: missing required section: {section}')
    except:
        pass
    if errors:
        print('\n'.join(errors), file=sys.stderr)
except:
    pass
"
